     1→/* ──────────────────────────────────────────────────────
     2→   Jake OS — Fábrica de Criativos v2
     3→────────────────────────────────────────────────────── */
     4→(function () {
     5→  'use strict';
     6→
     7→  // ── Estado ─────────────────────────────────────────
     8→  var _tipo        = 'imagem';   // 'imagem' | 'video'
     9→  var _modo        = 'anuncios'; // modo do especialista
    10→  var _modelo      = 'flux-1.1-pro';
    11→  var _promptExp   = '';
    12→  var _resultadoUrl= '';
    13→  var _uploadUrl   = '';         // URL Replicate da imagem uploadada (para I2V)
    14→  var _uploadB64   = '';         // base64 da imagem (para análise)
    15→  var _uploadMime  = 'image/jpeg';
    16→  var _usarI2V     = false;
    17→  var _predId      = '';         // prediction_id do vídeo em andamento
    18→  var _pollTimer   = null;
    19→  var _histPage    = 1;
    20→  var _histFiltros = { folder_id: '', tipo: '' };
    21→
    22→  // ── Definição de modelos ────────────────────────────
    23→  var _MODELOS_IMAGEM = [
    24→    { key:'flux-1.1-pro',    nome:'Flux 1.1 Pro',       vel:'fast', custo:2 },
    25→    { key:'flux-dev',        nome:'Flux Dev',            vel:'med',  custo:2 },
    26→    { key:'recraft-v3',      nome:'Recraft V3',          vel:'fast', custo:2 },
    27→    { key:'ideogram-v3-turbo',nome:'Ideogram V3 Turbo', vel:'fast', custo:1 },
    28→    { key:'imagen-4',        nome:'Imagen 4',            vel:'med',  custo:3 },
    29→  ];
    30→  var _MODELOS_VIDEO = [
    31→    { key:'wan-t2v-fast',  nome:'Wan T2V Fast',     tipo:'T2V', vel:'fast', custo:1 },
    32→    { key:'wan-5b-fast',   nome:'Wan 5B Fast',      tipo:'T2V', vel:'med',  custo:2 },
    33→    { key:'hailuo-02',     nome:'Hailuo 02 Fast',   tipo:'T2V', vel:'fast', custo:2 },
    34→    { key:'seedance-lite', nome:'Seedance Lite',    tipo:'T2V', vel:'med',  custo:2 },
    35→    { key:'runway-gen4',   nome:'Runway Gen-4',     tipo:'T2V', vel:'fast', custo:3 },
    36→    { key:'wan-i2v-fast',  nome:'Wan I2V Fast',     tipo:'I2V', vel:'fast', custo:1 },
    37→  ];
    38→
    39→  // ── Init ───────────────────────────────────────────
    40→  function init() {
    41→    bindTipoToggle();
    42→    bindModos();
    43→    renderModelos();
    44→    bindUpload();
    45→    bindPromptActions();
    46→    bindGerarBtn();
    47→    bindResultadoAcoes();
    48→    bindAbas();
    49→    bindHistoricoEvents();
    50→    carregarPastas();
    51→    carregarHistorico();
    52→  }
    53→
    54→  // ── Toggle Imagem / Vídeo ───────────────────────────
    55→  function bindTipoToggle() {
    56→    var btnImg = document.getElementById('cri-tipo-imagem');
    57→    var btnVid = document.getElementById('cri-tipo-video');
    58→    if (btnImg) btnImg.addEventListener('click', function () {
    59→      _tipo = 'imagem'; _modelo = 'flux-1.1-pro'; _usarI2V = false;
    60→      btnImg.classList.add('active'); btnVid.classList.remove('active');
    61→      renderModelos();
    62→      _setText('cri-modelos-label', 'Modelo de imagem');
    63→    });
    64→    if (btnVid) btnVid.addEventListener('click', function () {
    65→      _tipo = 'video'; _modelo = 'wan-t2v-fast';
    66→      btnVid.classList.add('active'); btnImg.classList.remove('active');
    67→      renderModelos();
    68→      _setText('cri-modelos-label', 'Modelo de vídeo');
    69→    });
    70→  }
    71→
    72→  // ── Seletor de Modo ─────────────────────────────────
    73→  function bindModos() {
    74→    document.querySelectorAll('.cri-modo-card').forEach(function (card) {
    75→      card.addEventListener('click', function () {
    76→        _modo = this.dataset.modo;
    77→        document.querySelectorAll('.cri-modo-card').forEach(function (c) { c.classList.remove('active'); });
    78→        this.classList.add('active');
    79→        esconder('cri-expandido-painel'); _promptExp = '';
    80→      });
    81→    });
    82→  }
    83→
    84→  // ── Render modelos ──────────────────────────────────
    85→  function renderModelos() {
    86→    var grid = document.getElementById('cri-modelos-grid');
    87→    if (!grid) return;
    88→    var lista = _tipo === 'imagem' ? _MODELOS_IMAGEM : _MODELOS_VIDEO;
    89→    grid.innerHTML = lista.map(function (m) {
    90→      var ativo = m.key === _modelo ? ' active' : '';
    91→      var disabled = (m.tipo === 'I2V' && !_usarI2V) ? ' disabled' : '';
    92→      var badges = '';
    93→      if (_tipo === 'imagem') {
    94→        badges = '<span class="cri-badge cri-badge-tipo-imagem">IMG</span>';
    95→      } else {
    96→        badges = '<span class="cri-badge cri-badge-tipo-' + (m.tipo === 'I2V' ? 'i2v' : 't2v') + '">' + m.tipo + '</span>';
    97→      }
    98→      badges += '<span class="cri-badge cri-badge-vel-' + m.vel + '">' + (m.vel === 'fast' ? '⚡' : '◑') + '</span>';
    99→      badges += '<span class="cri-badge cri-badge-custo-' + m.custo + '">' + '$'.repeat(m.custo) + '</span>';
   100→      return '<div class="cri-modelo-card' + ativo + disabled + '" data-key="' + m.key + '">' +
   101→        '<span class="cri-modelo-nome">' + _esc(m.nome) + '</span>' +
   102→        '<div class="cri-modelo-badges">' + badges + '</div></div>';
   103→    }).join('');
   104→    grid.querySelectorAll('.cri-modelo-card:not(.disabled)').forEach(function (card) {
   105→      card.addEventListener('click', function () {
   106→        _modelo = this.dataset.key;
   107→        grid.querySelectorAll('.cri-modelo-card').forEach(function (c) { c.classList.remove('active'); });
   108→        this.classList.add('active');
   109→      });
   110→    });
   111→  }
   112→
   113→  // ── Utilitários ─────────────────────────────────────
   114→  function _val(id) { var el = document.getElementById(id); return el ? el.value : ''; }
   115→  function _set(id, v) { var el = document.getElementById(id); if (el) el.value = v || ''; }
   116→  function _setText(id, t) { var el = document.getElementById(id); if (el) el.textContent = t || ''; }
   117→  function _esc(s) { return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }
   118→  function mostrar(id) { var el = document.getElementById(id); if (el) el.classList.remove('hidden'); }
   119→  function esconder(id) { var el = document.getElementById(id); if (el) el.classList.add('hidden'); }
   120→
   121→  // ── Observer para init lazy ─────────────────────────
   122→  var _iniciado = false;
   123→  var _obs = new MutationObserver(function (muts) {
   124→    muts.forEach(function (m) {
   125→      if (m.target.id === 'page-criativos' && m.target.classList.contains('active')) {
   126→        if (!_iniciado) { _iniciado = true; init(); }
   127→      }
   128→    });
   129→  });
   130→  var page = document.getElementById('page-criativos');
   131→  if (page) {
   132→    _obs.observe(page, { attributes: true, attributeFilter: ['class'] });
   133→    if (page.classList.contains('active')) { _iniciado = true; init(); }
   134→  }
   135→
   136→  // ── Stubs para tasks seguintes ──────────────────────
   137→  function bindUpload() {
   138→    var zone  = document.getElementById('cri-upload-zone');
   139→    var input = document.getElementById('cri-upload-input');
   140→    if (!zone || !input) return;
   141→    zone.addEventListener('dragover', function (e) { e.preventDefault(); zone.classList.add('dragover'); });
   142→    zone.addEventListener('dragleave', function () { zone.classList.remove('dragover'); });
   143→    zone.addEventListener('drop', function (e) {
   144→      e.preventDefault(); zone.classList.remove('dragover');
   145→      var f = e.dataTransfer.files[0]; if (f) _processarUpload(f);
   146→    });
   147→    input.addEventListener('change', function () { if (this.files[0]) _processarUpload(this.files[0]); });
   148→    var btnI2V = document.getElementById('cri-btn-i2v');
   149→    var btnAna = document.getElementById('cri-btn-analisar');
   150→    var btnRem = document.getElementById('cri-btn-remover-img');
   151→    if (btnI2V) btnI2V.addEventListener('click', function () {
   152→      _usarI2V = true;
   153→      if (_tipo !== 'video') {
   154→        _tipo = 'video';
   155→        document.getElementById('cri-tipo-video').classList.add('active');
   156→        document.getElementById('cri-tipo-imagem').classList.remove('active');
   157→        _modelo = 'wan-i2v-fast';
   158→        _setText('cri-modelos-label', 'Modelo de vídeo');
   159→      } else {
   160→        _modelo = 'wan-i2v-fast';
   161→      }
   162→      renderModelos();
   163→      alert('Imagem definida como input I2V. Modelo Wan I2V Fast selecionado.');
   164→    });
   165→    if (btnAna) btnAna.addEventListener('click', _analisarReferencia);
   166→    if (btnRem) btnRem.addEventListener('click', function () {
   167→      _uploadUrl = ''; _uploadB64 = ''; _usarI2V = false;
   168→      esconder('cri-upload-preview-wrap'); mostrar('cri-upload-placeholder');
   169→      document.getElementById('cri-upload-input').value = '';
   170→      renderModelos();
   171→    });
   172→  }
   173→
   174→  function _processarUpload(file) {
   175→    var reader = new FileReader();
   176→    reader.onload = function (e) {
   177→      var img = document.getElementById('cri-upload-img');
   178→      if (img) { img.src = e.target.result; }
   179→      esconder('cri-upload-placeholder'); mostrar('cri-upload-preview-wrap');
   180→    };
   181→    reader.readAsDataURL(file);
   182→    // Upload para Replicate
   183→    var fd = new FormData();
   184→    fd.append('arquivo', file);
   185→    fetch('/api/criativos/upload-imagem', { method: 'POST', body: fd })
   186→      .then(function (r) { return r.json(); })
   187→      .then(function (data) {
   188→        if (data.error) { alert('Erro no upload: ' + data.error); return; }
   189→        _uploadUrl  = data.url   || '';
   190→        _uploadB64  = data.base64 || '';
   191→        _uploadMime = data.mime_type || 'image/jpeg';
   192→      })
   193→      .catch(function (e) { alert('Erro de rede no upload: ' + e); });
   194→  }
   195→
   196→  function _analisarReferencia() {
   197→    if (!_uploadB64) { alert('Faça upload de uma imagem primeiro.'); return; }
   198→    _setLoading('🔍 Analisando estilo da imagem...');
   199→    fetch('/api/criativos/analisar-referencia', {
   200→      method: 'POST',
   201→      headers: { 'Content-Type': 'application/json' },
   202→      body: JSON.stringify({ imagem_base64: _uploadB64, mime_type: _uploadMime }),
   203→    })
   204→      .then(function (r) { return r.json(); })
   205→      .then(function (data) {
   206→        _clearLoading();
   207→        if (data.error) { alert('Erro na análise: ' + data.error); return; }
   208→        _set('cri-prompt', '(Analisado da referência)');
   209→        _promptExp = data.prompt_sugerido || '';
   210→        // Selecionar modo sugerido
   211→        if (data.modo_sugerido) {
   212→          _modo = data.modo_sugerido;
   213→          document.querySelectorAll('.cri-modo-card').forEach(function (c) {
   214→            c.classList.toggle('active', c.dataset.modo === _modo);
   215→          });
   216→        }
   217→        _setText('cri-expandido-original', 'Gerado a partir da análise da referência');
   218→        _set('cri-expandido-texto', _promptExp);
   219→        mostrar('cri-expandido-painel');
   220→      })
   221→      .catch(function (e) { _clearLoading(); alert('Erro: ' + e); });
   222→  }
   223→
   224→  function bindPromptActions() {
   225→    var btnReg = document.getElementById('cri-btn-regerar');
   226→    if (btnReg) btnReg.addEventListener('click', _expandirPrompt);
   227→  }
   228→
   229→  function _expandirPrompt(callback) {
   230→    var prompt = _val('cri-prompt').trim();
   231→    if (!prompt || prompt === '(Analisado da referência)') {
   232→      if (_promptExp && typeof callback === 'function') { callback(); return; }
   233→      alert('Digite um prompt antes de gerar.'); return;
   234→    }
   235→    _setLoading('✨ Claude expandindo o prompt...');
   236→    fetch('/api/criativos/expandir-prompt', {
   237→      method: 'POST',
   238→      headers: { 'Content-Type': 'application/json' },
   239→      body: JSON.stringify({ prompt: prompt, modo: _modo, tipo: _tipo }),
   240→    })
   241→      .then(function (r) { return r.json(); })
   242→      .then(function (data) {
   243→        _clearLoading();
   244→        if (data.error) { alert('Erro ao expandir: ' + data.error); return; }
   245→        _promptExp = data.prompt_expandido || '';
   246→        _setText('cri-expandido-original', 'Original: ' + prompt);
   247→        _set('cri-expandido-texto', _promptExp);
   248→        mostrar('cri-expandido-painel');
   249→        if (typeof callback === 'function') callback();
   250→      })
   251→      .catch(function (e) { _clearLoading(); alert('Erro: ' + e); });
   252→  }
   253→
   254→  function bindGerarBtn() {
   255→    var btn = document.getElementById('cri-btn-gerar');
   256→    if (btn) btn.addEventListener('click', function () {
   257→      // Prompt expandido já existe? Ir direto para geração
   258→      var promptFinal = _val('cri-expandido-texto').trim() || _promptExp;
   259→      if (promptFinal) {
   260→        _promptExp = promptFinal;
   261→        _gerar();
   262→      } else {
   263→        // Expandir primeiro, depois gerar
   264→        _expandirPrompt(function () { _gerar(); });
   265→      }
   266→    });
   267→  }
   268→
   269→  function _gerar() {
   270→    if (_tipo === 'imagem') {
   271→      _gerarImagem();
   272→    } else {
   273→      _gerarVideo();
   274→    }
   275→  }
   276→
   277→  function _gerarImagem() {
   278→    _setLoading('🖼️ Gerando imagem...', 40);
   279→    fetch('/api/criativos/gerar-imagem', {
   280→      method: 'POST',
   281→      headers: { 'Content-Type': 'application/json' },
   282→      body: JSON.stringify({ prompt_expandido: _promptExp, modelo: _modelo }),
   283→    })
   284→      .then(function (r) { return r.json(); })
   285→      .then(function (data) {
   286→        _clearLoading();
   287→        if (data.error) { alert('Erro na geração: ' + data.error); return; }
   288→        _resultadoUrl = data.url;
   289→        _mostrarResultado('imagem');
   290→      })
   291→      .catch(function (e) { _clearLoading(); alert('Erro: ' + e); });
   292→  }
   293→
   294→  function _gerarVideo() {
   295→    _setLoading('🎬 Iniciando geração de vídeo...', 10);
   296→    var payload = { prompt_expandido: _promptExp, modelo: _modelo };
   297→    if (_usarI2V && _uploadUrl) payload.imagem_url = _uploadUrl;
   298→    fetch('/api/criativos/gerar-video', {
   299→      method: 'POST',
   300→      headers: { 'Content-Type': 'application/json' },
   301→      body: JSON.stringify(payload),
   302→    })
   303→      .then(function (r) { return r.json(); })
   304→      .then(function (data) {
   305→        if (data.error) { _clearLoading(); alert('Erro: ' + data.error); return; }
   306→        _predId = data.prediction_id;
   307→        _pollVideo(0);
   308→      })
   309→      .catch(function (e) { _clearLoading(); alert('Erro: ' + e); });
   310→  }
   311→
   312→  function _pollVideo(tentativa) {
   313→    var progresso = Math.min(10 + tentativa * 4, 85);
   314→    _setLoading('🎬 Gerando vídeo (' + (tentativa * 3) + 's)...', progresso);
   315→    fetch('/api/criativos/status/' + _predId)
   316→      .then(function (r) { return r.json(); })
   317→      .then(function (data) {
   318→        if (data.status === 'succeeded') {
   319→          _clearLoading(); _resultadoUrl = data.url; _mostrarResultado('video');
   320→        } else if (data.status === 'failed') {
   321→          _clearLoading(); alert('Geração falhou: ' + (data.error || 'erro desconhecido'));
   322→        } else {
   323→          // Continuar polling
   324→          _pollTimer = setTimeout(function () { _pollVideo(tentativa + 1); }, 3000);
   325→        }
   326→      })
   327→      .catch(function () { _pollTimer = setTimeout(function () { _pollVideo(tentativa + 1); }, 3000); });
   328→  }
   329→
   330→  function _setLoading(texto, progresso) {
   331→    esconder('cri-empty'); esconder('cri-preview-wrap'); esconder('cri-acoes');
   332→    mostrar('cri-loading-wrap');
   333→    _setText('cri-loading-text', texto);
   334→    var fill = document.getElementById('cri-progress-fill');
   335→    if (fill && progresso) fill.style.width = progresso + '%';
   336→    var btn = document.getElementById('cri-btn-gerar');
   337→    if (btn) { btn.textContent = 'Gerando...'; btn.classList.add('loading'); }
   338→  }
   339→
   340→  function _clearLoading() {
   341→    esconder('cri-loading-wrap');
   342→    var btn = document.getElementById('cri-btn-gerar');
   343→    if (btn) { btn.textContent = '✦ Gerar Criativo'; btn.classList.remove('loading'); }
   344→  }
   345→
   346→  function _mostrarResultado(tipo) {
   347→    esconder('cri-empty'); esconder('cri-loading-wrap');
   348→    mostrar('cri-preview-wrap'); mostrar('cri-acoes');
   349→    var img = document.getElementById('cri-preview-img');
   350→    var vid = document.getElementById('cri-preview-video');
   351→    if (tipo === 'imagem') {
   352→      if (img) { img.src = _resultadoUrl; img.classList.remove('hidden'); }
   353→      if (vid) vid.classList.add('hidden');
   354→    } else {
   355→      if (vid) { vid.src = _resultadoUrl; vid.classList.remove('hidden'); }
   356→      if (img) img.classList.add('hidden');
   357→    }
   358→  }
   359→  function bindResultadoAcoes() {}
   360→  function bindAbas() {}
   361→  function bindHistoricoEvents() {}
   362→  function carregarPastas() {}
   363→  function carregarHistorico() {}
   364→
   365→})();
